namespace sv_41c54f77c14b47409a8a5b044001cf66.Services;

public class WizardState
{
    // Step 1: Personal Info
    public string FullName { get; set; } = "";
    public string Email { get; set; } = "";

    // Step 2: Experience
    public List<JobEntry> JobHistory { get; set; } = [];

    // Step 3: References
    public List<Reference> References { get; set; } = [];

    // Progress tracking
    public HashSet<int> CompletedSteps { get; set; } = [];
    public int CurrentStep { get; set; } = 1;
}

public class JobEntry
{
    public string Company { get; set; } = "";
    public string Title { get; set; } = "";
    public string Years { get; set; } = "";
}

public class Reference
{
    public string Name { get; set; } = "";
    public string Relationship { get; set; } = "";
    public string Phone { get; set; } = "";
}

using System.Collections.Concurrent;

namespace sv_41c54f77c14b47409a8a5b044001cf66.Services;

/// <summary>
/// Singleton store keyed by session ID. Each browser tab gets its own
/// WizardState via a cookie, so two applicants never share data.
/// </summary>
public class WizardStateStore
{
    public const string CookieName = "WizardSessionId";

    private readonly ConcurrentDictionary<string, WizardState> _sessions = new();

    public WizardState GetOrCreate(string sessionId) =>
        _sessions.GetOrAdd(sessionId, _ => new WizardState());

    public void Remove(string sessionId) =>
        _sessions.TryRemove(sessionId, out _);
}

