﻿@inherits LayoutComponentBase
@using sv_41c54f77c14b47409a8a5b044001cf66.Services
@inject WizardStateStore Store
@inject IHttpContextAccessor HttpContextAccessor

@{
    var isWizardPage = NavigationManager.Uri.Contains("/apply/", StringComparison.OrdinalIgnoreCase);
    WizardState? wizard = null;
    if (isWizardPage)
    {
        var sessionId = HttpContextAccessor.HttpContext?.Request.Cookies[WizardStateStore.CookieName];
        if (sessionId is not null)
        {
            wizard = Store.GetOrCreate(sessionId);
        }
    }
}

<div class="page">
    <div class="sidebar">
        <NavMenu />
    </div>

    <main>
        <div class="top-row px-4">
            @if (isWizardPage && wizard is not null)
            {
                <nav aria-label="Wizard progress" class="d-flex align-items-center gap-3 flex-grow-1">
                    @for (int i = 1; i <= 4; i++)
                    {
                        var step = i;
                        var label = step switch
                        {
                            1 => "Personal Info",
                            2 => "Experience",
                            3 => "References",
                            _ => "Review"
                        };
                        var isCompleted = wizard.CompletedSteps.Contains(step);
                        var isCurrent = wizard.CurrentStep == step;
                        var badgeClass = isCompleted ? "bg-success" : isCurrent ? "bg-primary" : "bg-secondary";

                        <span class="badge @badgeClass">
                            @step. @label @(isCompleted ? "✓" : "")
                        </span>
                    }
                    <span class="ms-auto text-muted">Step @wizard.CurrentStep of 4</span>
                </nav>
            }
            else
            {
                <a href="https://learn.microsoft.com/aspnet/core/" target="_blank">About</a>
            }
        </div>

        <article class="content px-4">
            @Body
        </article>
    </main>
</div>

<div id="blazor-error-ui" data-nosnippet>
    An unhandled error has occurred.
    <a href="." class="reload">Reload</a>
    <span class="dismiss">🗙</span>
</div>

