@page "/apply/personal-info"
@rendermode InteractiveServer
@using sv_41c54f77c14b47409a8a5b044001cf66.Services
@inject WizardStateStore Store
@inject IHttpContextAccessor HttpContextAccessor
@inject NavigationManager Nav

<PageTitle>Apply – Personal Info</PageTitle>
<h1>Step 1: Personal Information</h1>

@if (_wizard is not null)
{
    <div class="mb-3">
        <label class="form-label">Full Name</label>
        <input class="form-control" @bind="_wizard.FullName" />
    </div>
    <div class="mb-3">
        <label class="form-label">Email</label>
        <input class="form-control" type="email" @bind="_wizard.Email" />
    </div>
    <button class="btn btn-primary" @onclick="Next">Next →</button>
}

@code {
    private WizardState? _wizard;
    private string? _sessionId;

    protected override void OnInitialized()
    {
        // Capture session ID during prerender (HttpContext is available here).
        _sessionId ??= HttpContextAccessor.HttpContext?.Request.Cookies[WizardStateStore.CookieName];
        if (_sessionId is not null)
        {
            _wizard = Store.GetOrCreate(_sessionId);
            _wizard.CurrentStep = 1;
        }
    }

    private void Next()
    {
        if (_wizard is null) return;
        _wizard.CompletedSteps.Add(1);
        Nav.NavigateTo("/apply/experience");
    }
}

@page "/apply/experience"
@rendermode InteractiveServer
@using sv_41c54f77c14b47409a8a5b044001cf66.Services
@inject WizardStateStore Store
@inject IHttpContextAccessor HttpContextAccessor
@inject NavigationManager Nav

<PageTitle>Apply – Experience</PageTitle>
<h1>Step 2: Work Experience</h1>

@if (_wizard is not null)
{
    @foreach (var job in _wizard.JobHistory)
    {
        <div class="card mb-2 p-2">
