@page "/apply/review"
@rendermode InteractiveServer
@using sv_41c54f77c14b47409a8a5b044001cf66.Services
@inject WizardStateStore Store
@inject IHttpContextAccessor HttpContextAccessor
@inject NavigationManager Nav

<PageTitle>Apply – Review</PageTitle>
<h1>Step 4: Review Your Application</h1>

@if (_wizard is not null)
{
    <h4>Personal Information</h4>
    <p><strong>Name:</strong> @_wizard.FullName</p>
    <p><strong>Email:</strong> @_wizard.Email</p>

    <h4>Work Experience</h4>
    @if (_wizard.JobHistory.Count == 0)
    {
        <p class="text-muted">No jobs added.</p>
    }
    else
    {
        <ul>
            @foreach (var job in _wizard.JobHistory)
            {
                <li>@job.Title at @job.Company (@job.Years)</li>
            }
        </ul>
    }

    <h4>References</h4>
    @if (_wizard.References.Count == 0)
    {
        <p class="text-muted">No references added.</p>
    }
    else
    {
        <ul>
            @foreach (var r in _wizard.References)
            {
                <li>@r.Name – @r.Relationship (@r.Phone)</li>
            }
        </ul>
    }

    <div class="d-flex gap-2 mt-3">
        <button class="btn btn-secondary" @onclick="Back">← Back</button>
        <button class="btn btn-success" @onclick="Submit">Submit Application</button>
    </div>

    @if (_submitted)
    {
        <div class="alert alert-success mt-3">Application submitted!</div>
    }
}

@code {
    private WizardState? _wizard;
    private string? _sessionId;
    private bool _submitted;

    protected override void OnInitialized()
    {
        _sessionId ??= HttpContextAccessor.HttpContext?.Request.Cookies[WizardStateStore.CookieName];
        if (_sessionId is not null)
        {
            _wizard = Store.GetOrCreate(_sessionId);
            _wizard.CurrentStep = 4;
        }
    }

    private void Back() => Nav.NavigateTo("/apply/references");

    private void Submit()
    {
        if (_wizard is null || _sessionId is null) return;
        _wizard.CompletedSteps.Add(4);
        _submitted = true;
        // In production: save to DB, then remove session state.
        // Store.Remove(_sessionId);
    }
}

